file.snippet:
export const lessonSchema = z.object({
  title: z.string().min(3).max(100),
  durationMinutes: z.number().min(1).max(120),
  corePractice: z.string().min(3),
  keyPoint: z.string().min(3),
  tone: z.enum(['calming', 'energizing', 'neutral', 'visualization']),
});

interface LessonListItemProps {
  lesson: Lesson;
  onEdit?: (lesson: Lesson) => void;
  onDelete?: (lesson: Lesson) => void;
}
// Edit button onClick={() => onEdit?.(lesson)}

interface LessonListProps {
  onEditLesson?: (lesson: Lesson) => void;
  // ... other props
}
// Passes to LessonListItem: onEdit={onEditLesson}

interface.request:
{
  "lesson": {
    "title"?: string | null,
    "core_practice"?: string | null,
    "key_point"?: string | null,
    "tone"?: string | null,
    "duration_minutes"?: number | null
  }
}

interface.signature:
interface LessonEditProps {
  courseSlug: string;
  lesson: Lesson;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess?: () => void;
}

// Invalidate lessons list after update
['get', '/api/courses/{slug}/lessons', { params: { path: { slug: courseSlug } } }]

// Invalidate course detail for lesson count
['get', '/api/courses/{slug}', { params: { path: { slug: courseSlug } } }]
